1	export type Customer = { yearsWithMHPCO: number };
2	export type Item = {
3	  type: string;
4	  material?: string;
5	  enchantment?: number;
6	  cursed?: boolean;
7	};
8	export type Damage = { itemType: string; amount: number };
9	export type Incident = { cause?: string; damages: Damage[] };
10	
11	const PROCESSING_FEE = 5;
12	
13	const BASE_PRICES: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	  moonstone: 25,
20	};
21	
22	const INSURANCE_VALUES: Record<string, number> = {
23	  sword: 1000,
24	  amulet: 600,
25	  staff: 800,
26	  potion: 400,
27	  rune: 250,
28	  moonstone: 250,
29	};
30	
31	const COMPONENT_TYPES = ["rune", "moonstone"];
32	const BLOCK_SIZE = 3;
33	const BLOCK_PRICE = 60;
34	
35	const CURSED_SURCHARGE = 0.5;
36	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
37	const HIGH_ENCHANTMENT_THRESHOLD = 5;
38	const LOYALTY_DISCOUNT = 0.2;
39	const LOYALTY_YEARS_THRESHOLD = 2;
40	const FIRST_INSURANCE_SURCHARGE = 0.1;
41	const FOLLOWUP_DISCOUNT = 0.15;
42	
43	const isKnownItemType = (type: string): boolean => type in BASE_PRICES;
44	
45	const basePriceFor = (type: string): number => BASE_PRICES[type] ?? 0;
46	
47	const isComponentType = (type: string): boolean =>
48	  COMPONENT_TYPES.includes(type);
49	
50	const assertKnownItemTypes = (items: Item[]): void => {
51	  const unknown = items.find((item) => !isKnownItemType(item.type));
52	  if (unknown) throw new Error(`Unknown item type: ${unknown.type}`);
53	};
54	
55	const itemSurchargeRate = (item: Item): number => {
56	  let rate = 0;
57	  if (item.cursed) rate += CURSED_SURCHARGE;
58	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD)
59	    rate += HIGH_ENCHANTMENT_SURCHARGE;
60	  return rate;
61	};
62	
63	const groupByType = (items: Item[]): Map<string, Item[]> =>
64	  items.reduce((groups, item) => {
65	    const group = groups.get(item.type) ?? [];
66	    return groups.set(item.type, [...group, item]);
67	  }, new Map<string, Item[]>());
68	
69	const groupBasePremium = (type: string, group: Item[]): number => {
70	  if (isComponentType(type) && group.length === BLOCK_SIZE) return BLOCK_PRICE;
71	  return group.length * basePriceFor(type);
72	};
73	
74	const groupItemSurcharges = (type: string, group: Item[]): number => {
75	  // Components have no item-specific modifiers.
76	  if (isComponentType(type)) return 0;
77	  const unitBase = basePriceFor(type);
78	  return group.reduce((sum, item) => sum + unitBase * itemSurchargeRate(item), 0);
79	};
80	
81	const policyBasePremium = (items: Item[]): number =>
82	  Array.from(groupByType(items)).reduce(
83	    (sum, [type, group]) => sum + groupBasePremium(type, group),
84	    0,
85	  );
86	
87	const policyItemSurcharges = (items: Item[]): number =>
88	  Array.from(groupByType(items)).reduce(
89	    (sum, [type, group]) => sum + groupItemSurcharges(type, group),
90	    0,
91	  );
92	
93	const policyModifierRate = (
94	  customer: Customer,
95	  previousQuoteCount: number,
96	): number => {
97	  const loyalty =
98	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? -LOYALTY_DISCOUNT : 0;
99	  const followUp = previousQuoteCount >= 1 ? -FOLLOWUP_DISCOUNT : 0;
100	  return FIRST_INSURANCE_SURCHARGE + loyalty + followUp;
101	};
102	
103	export const quote = (
104	  customer: Customer,
105	  items: Item[],
106	  previousQuoteCount: number,
107	): number => {
108	  assertKnownItemTypes(items);
109	  const basePremium = policyBasePremium(items);
110	  const total =
111	    basePremium +
112	    policyItemSurcharges(items) +
113	    basePremium * policyModifierRate(customer, previousQuoteCount) +
114	    PROCESSING_FEE;
115	  return Math.ceil(total);
116	};
117	
118	const DEDUCTIBLE = 100;
119	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
120	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
121	const CAP_MULTIPLIER = 2;
122	
123	const insuranceSum = (items: Item[]): number =>
124	  items.reduce((sum, i) => sum + (INSURANCE_VALUES[i.type] ?? 0), 0);
125	
126	const policyCap = (items: Item[]): number =>
127	  insuranceSum(items) * CAP_MULTIPLIER;
128	
129	const isHighlyEnchanted = (item: Item | undefined): boolean =>
130	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
131	
132	const reimbursableAmount = (item: Item | undefined, damageAmount: number): number =>
133	  isHighlyEnchanted(item)
134	    ? damageAmount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
135	    : damageAmount;
136	
137	const damagePayout = (items: Item[], damage: Damage): number => {
138	  const item = items.find((i) => i.type === damage.itemType);
139	  return reimbursableAmount(item, damage.amount) - DEDUCTIBLE;
140	};
141	
142	const desiredPayout = (items: Item[], incident: Incident): number =>
143	  incident.damages.reduce((sum, d) => sum + damagePayout(items, d), 0);
144	
145	const assertDamagesMatchPolicy = (items: Item[], incident: Incident): void => {
146	  const damageCounts = new Map<string, number>();
147	  for (const d of incident.damages) {
148	    if (d.amount < 0)
149	      throw new Error(`Damage amount must be non-negative: ${d.amount}`);
150	    if (!items.some((i) => i.type === d.itemType))
151	      throw new Error(`Damage references item not in policy: ${d.itemType}`);
152	    damageCounts.set(d.itemType, (damageCounts.get(d.itemType) ?? 0) + 1);
153	  }
154	  for (const [type, count] of damageCounts) {
155	    const insuredCount = items.filter((i) => i.type === type).length;
156	    if (count > insuredCount)
157	      throw new Error(
158	        `More damages of ${type} (${count}) than insured (${insuredCount})`,
159	      );
160	  }
161	};
162	
163	export const claim = (
164	  _customer: Customer,
165	  items: Item[],
166	  incident: Incident,
167	  capUsed: number,
168	): { payout: number; remainingCap: number } => {
169	  assertDamagesMatchPolicy(items, incident);
170	  const remainingBeforeClaim = policyCap(items) - capUsed;
171	  const payout = Math.floor(
172	    Math.min(desiredPayout(items, incident), remainingBeforeClaim),
173	  );
174	  return { payout, remainingCap: remainingBeforeClaim - payout };
175	};
