const assertDamagesMatchPolicy = (items: Item[], incident: Incident): void => {
  const damageCounts = new Map<string, number>();
  for (const d of incident.damages) {
    if (d.amount < 0)
      throw new Error(`Damage amount must be non-negative: ${d.amount}`);
    if (!items.some((i) => i.type === d.itemType))
      throw new Error(`Damage references item not in policy: ${d.itemType}`);
    damageCounts.set(d.itemType, (damageCounts.get(d.itemType) ?? 0) + 1);
  }
  for (const [type, count] of damageCounts) {
    const insuredCount = items.filter((i) => i.type === type).length;
    if (count > insuredCount)
      throw new Error(
        `More damages of ${type} (${count}) than insured (${insuredCount})`,
      );
  }
};

